using namespace std;

int main()
{
	int n,sum,b=0,a,ans=0;
    scanf("%d",&n);
    sum=n*n;
    while(ans<sum)
	{
        scanf("%d",&a);
        for(int i=1;i<=a;i++)
		{
            printf("%d",b);
            ans++;
            if(ans%n==0)
            {
            	printf("\n");
            }
        }
        b=1-b;
    }
    return 0;
}
